public class AppointmentService
{
    private static readonly List<string> Doctors =
    [
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Williams",
        "Dr. Brown"
    ];

    private static readonly Dictionary<string, List<string>> DoctorTimeSlots = new()
    {
        ["Dr. Smith"] = ["9:00 AM", "10:00 AM", "11:00 AM", "2:00 PM", "3:00 PM"],
        ["Dr. Johnson"] = ["8:00 AM", "10:00 AM", "1:00 PM", "4:00 PM"],
        ["Dr. Williams"] = ["9:30 AM", "11:30 AM", "2:30 PM", "4:30 PM"],
        ["Dr. Brown"] = ["8:30 AM", "10:00 AM", "12:00 PM", "3:30 PM"],
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        if (DoctorTimeSlots.TryGetValue(doctor, out var slots))
        {
            return Task.FromResult(slots);
        }

        return Task.FromResult(new List<string>());
    }

    /// <summary>
    /// Validates server-side business rules. Returns a dictionary of
    /// field name → error message for any failing rules, or an empty
    /// dictionary when everything passes.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        // Outstanding balance check
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(BookAppointmentModel.Email)] = "Account has outstanding balance";
        }

        // Self-pay check
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors[nameof(BookAppointmentModel.Doctor)] =
                "Selected doctor does not accept self-pay patients";
        }

        // Race-condition: slot just taken
        if (timeSlot == "10:00 AM")
        {
            errors[nameof(BookAppointmentModel.TimeSlot)] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

public class BookAppointmentModel
{
    // Step 1
    public string PatientName { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2
    public string Doctor { get; set; } = string.Empty;
    public DateTime? AppointmentDate { get; set; }
    public string TimeSlot { get; set; } = string.Empty;
    public string ReasonForVisit { get; set; } = string.Empty;
}
"}

