@page "/book-appointment"
@rendermode InteractiveServer
@using sv_4f7331d360184092be38a9ea82c45edb.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3 class="mb-4">Book a Medical Appointment</h3>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Appointment Requested!</h4>
        <p>
            Thank you, <strong>@_model.PatientName</strong>. Your appointment with
            <strong>@_model.Doctor</strong> on
            <strong>@_model.AppointmentDate?.ToString("MMMM d, yyyy")</strong> at
            <strong>@_model.TimeSlot</strong> has been submitted.
        </p>
        <button class="btn btn-primary" @onclick="ResetForm">Book Another</button>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="book-appointment">
        <DataAnnotationsValidator />

        @* ───── STEP 1 ───── *@
        <fieldset>
            <legend>Step 1: Patient Information</legend>

            <div class="mb-3">
                <label class="form-label" for="patientName">Patient Name</label>
                <InputText id="patientName" class="form-control" @bind-Value="_model.PatientName" />
                <ValidationMessage For="() => _model.PatientName" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="email">Email</label>
                <InputText id="email" class="form-control" @bind-Value="_model.Email" />
                <ValidationMessage For="() => _model.Email" />
                @if (_serverErrors.ContainsKey(nameof(_model.Email)))
                {
                    <div class="validation-message">@_serverErrors[nameof(_model.Email)]</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="phone">Phone</label>
                <InputText id="phone" class="form-control" @bind-Value="_model.Phone" />
                <ValidationMessage For="() => _model.Phone" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="insurance">Insurance Provider</label>
                <InputSelect id="insurance" class="form-select" @bind-Value="_model.InsuranceProvider">
                    <option value="">-- Select --</option>
                    <option value="Aetna">Aetna</option>
                    <option value="BlueCross">BlueCross</option>
                    <option value="Cigna">Cigna</option>
                    <option value="UnitedHealth">UnitedHealth</option>
                    <option value="None">None</option>
                </InputSelect>
                <ValidationMessage For="() => _model.InsuranceProvider" />
            </div>

            @if (!_showStep2)
            {
                <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                    Next &raquo;
                </button>
            }
        </fieldset>

        @* ───── STEP 2 ───── *@
        @if (_showStep2)
        {
            <fieldset class="mt-4">
                <legend>Step 2: Appointment Details</legend>

                <div class="mb-3">
                    <label class="form-label" for="doctor">Preferred Doctor</label>
                    <InputSelect id="doctor" class="form-select"
                                 @bind-Value="_model.Doctor"
                                 @bind-Value:after="OnDoctorOrDateChanged">
                        <option value="">-- Select --</option>
                        @foreach (var doc in _doctors)
                        {
                            <option value="@doc">@doc</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.Doctor" />
                    @if (_serverErrors.ContainsKey(nameof(_model.Doctor)))
                    {
                        <div class="validation-message">@_serverErrors[nameof(_model.Doctor)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label" for="date">Appointment Date</label>
                    <InputDate id="date" class="form-control"
                               @bind-Value="_model.AppointmentDate"
                               @bind-Value:after="OnDoctorOrDateChanged" />
                    <ValidationMessage For="() => _model.AppointmentDate" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="timeslot">Time Slot</label>
                    <InputSelect id="timeslot" class="form-select" @bind-Value="_model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in _timeSlots)
                        {
                            <option value="@slot">@slot</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.TimeSlot" />
                    @if (_serverErrors.ContainsKey(nameof(_model.TimeSlot)))
                    {
                        <div class="validation-message">@_serverErrors[nameof(_model.TimeSlot)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label" for="reason">Reason for Visit</label>
                    <InputTextArea id="reason" class="form-control" rows="3"
                                   @bind-Value="_model.ReasonForVisit" />
                    <ValidationMessage For="() => _model.ReasonForVisit" />
                </div>

                <div class="d-flex gap-2">
                    <button type="button" class="btn btn-outline-secondary" @onclick="BackToStep1">
                        &laquo; Back
                    </button>
                    <button type="button" class="btn btn-info" @onclick="CheckAvailability"
                            disabled="@_checking">
                        @(_checking ? "Checking…" : "Check Availability")
                    </button>
                    <button type="submit" class="btn btn-success" disabled="@(!_availabilityChecked)">
                        Confirm Appointment
                    </button>
                </div>
            </fieldset>
        }
    </EditForm>
}

@code {
    private BookAppointmentModel _model = new();
    private bool _showStep2;
    private bool _submitted;
    private bool _checking;
    private bool _availabilityChecked;

    private List<string> _doctors = [];
    private List<string> _timeSlots = [];
    private Dictionary<string, string> _serverErrors = new();

    private EditContext? _editContext;
    private ValidationMessageStore? _messageStore;

    protected override async Task OnInitializedAsync()
    {
        _doctors = await AppointmentSvc.GetDoctorsAsync();
        InitEditContext();
    }

    private void InitEditContext()
    {
        _editContext = new EditContext(_model);
        _messageStore = new ValidationMessageStore(_editContext);
        _editContext.OnFieldChanged += (_, args) =>
        {
            // Clear server errors for the changed field so the user can retry
            var fieldName = args.FieldIdentifier.FieldName;
            _serverErrors.Remove(fieldName);
            _messageStore?.Clear(args.FieldIdentifier);
            _availabilityChecked = false;
        };
    }

    private void ProceedToStep2()
    {
        _messageStore?.Clear();
        var valid = true;

        if (string.IsNullOrWhiteSpace(_model.PatientName))
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.PatientName)),
                "Patient Name is required.");
            valid = false;
        }

        if (string.IsNullOrWhiteSpace(_model.Email))
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.Email)),
                "Email is required.");
            valid = false;
        }
        else if (!IsValidEmail(_model.Email))
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.Email)),
                "Please enter a valid email address.");
            valid = false;
        }

        if (string.IsNullOrWhiteSpace(_model.Phone))
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.Phone)),
                "Phone is required.");
            valid = false;
        }

        if (string.IsNullOrWhiteSpace(_model.InsuranceProvider))
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.InsuranceProvider)),
                "Insurance Provider is required.");
            valid = false;
        }

        _editContext!.NotifyValidationStateChanged();

        if (valid)
        {
            _showStep2 = true;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        _availabilityChecked = false;
        _timeSlots = [];
        _model.TimeSlot = string.Empty;

        if (!string.IsNullOrEmpty(_model.Doctor) && _model.AppointmentDate.HasValue)
        {
            _timeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                _model.Doctor,
                DateOnly.FromDateTime(_model.AppointmentDate.Value));
        }
    }

    private async Task CheckAvailability()
    {
        _serverErrors.Clear();
        _messageStore?.Clear();
        var valid = true;

        // Client-side step 2 validation
        if (string.IsNullOrWhiteSpace(_model.Doctor))
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.Doctor)),
                "Please select a doctor.");
            valid = false;
        }

        if (!_model.AppointmentDate.HasValue)
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.AppointmentDate)),
                "Appointment date is required.");
            valid = false;
        }
        else if (_model.AppointmentDate.Value.Date <= DateTime.Today)
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.AppointmentDate)),
                "Appointment date must be in the future.");
            valid = false;
        }

        if (string.IsNullOrWhiteSpace(_model.TimeSlot))
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.TimeSlot)),
                "Please select a time slot.");
            valid = false;
        }

        if (string.IsNullOrWhiteSpace(_model.ReasonForVisit))
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.ReasonForVisit)),
                "Reason for visit is required.");
            valid = false;
        }
        else if (_model.ReasonForVisit.Length > 500)
        {
            _messageStore!.Add(_editContext!.Field(nameof(_model.ReasonForVisit)),
                "Reason for visit must be 500 characters or fewer.");
            valid = false;
        }

        _editContext!.NotifyValidationStateChanged();

        if (!valid)
        {
            return;
        }

        // Server-side validation
        _checking = true;

        try
        {
            _serverErrors = await AppointmentSvc.ValidatePatientAsync(
                _model.Email,
                _model.InsuranceProvider,
                _model.Doctor,
                _model.TimeSlot);

            if (_serverErrors.Count == 0)
            {
                _availabilityChecked = true;
            }
        }
        finally
        {
            _checking = false;
        }
    }

    private void HandleSubmit()
    {
        if (_availabilityChecked && _serverErrors.Count == 0)
        {
            _submitted = true;
        }
    }

    private void BackToStep1()
    {
        _showStep2 = false;
    }

    private void ResetForm()
    {
        _model = new BookAppointmentModel();
        _showStep2 = false;
        _submitted = false;
        _availabilityChecked = false;
        _serverErrors.Clear();
        _timeSlots = [];
        InitEditContext();
    }

    private static bool IsValidEmail(string email)
    {
        try
        {
            var addr = new System.Net.Mail.MailAddress(email);
            return addr.Address == email;
        }
        catch
        {
            return false;
        }
    }
}

